    print('No version changes detected.')
print()
print('All resolved versions:')
for k in sorted(a.keys()):
    bv = b.get(k, 'N/A')
    print(f'  {k[0]:8s} {k[1]:40s} baseline={bv:10s} after={a[k]}')
